      { "from": "Saga Orchestrator", "to": "Inventory Service", "contract": "reserveItems(orderId, items[]) → {success, reservationId} | releaseItems(reservationId) → {success}", "coupling_type": "command (async message or sync RPC with idempotency key)" },
      { "from": "Saga Orchestrator", "to": "Payment Service", "contract": "chargeCustomer(orderId, customerId, amount) → {success, paymentId} | refundPayment(paymentId) → {success}", "coupling_type": "command (async message or sync RPC with idempotency key)" },
      { "from": "Saga Orchestrator", "to": "Courier Service", "contract": "assignCourier(orderId, pickupLocation, dropoffLocation) → {success, courierId} | unassignCourier(orderId, courierId) → {success}", "coupling_type": "command (async message or sync RPC with idempotency key)" },
