      { "name": "Inventory", "classification": "supporting", "aggregates": ["Reservation (id, orderId, items, status: HELD|RELEASED)", "StockItem (sku, availableQty)"] },
      { "name": "Payment", "classification": "generic", "aggregates": ["PaymentTransaction (id, orderId, amount, status: CHARGED|REFUNDED)"] },
      { "name": "Courier Assignment", "classification": "core", "aggregates": ["CourierAssignment (id, orderId, courierId, status: ASSIGNED|UNASSIGNED)", "Courier (id, availability, location)"] },
      { "name": "Saga Coordination", "classification": "generic", "aggregates": ["SagaInstance (id, orderId, currentStep, status, stepOutcomes[])"] }
    ],
    "context_map": [
      { "upstream": "Saga Coordination", "downstream": "Order Management", "relationship": "Customer-Supplier — Orchestrator issues commands, Order Service fulfills" },
      { "upstream": "Saga Coordination", "downstream": "Inventory", "relationship": "Customer-Supplier" },
      { "upstream": "Saga Coordination", "downstream": "Payment", "relationship": "Customer-Supplier" },
      { "upstream": "Saga Coordination", "downstream": "Courier Assignment", "relationship": "Customer-Supplier" }
    ]
  },

  "trade_offs": [
    {
      "decision": "Orchestration over Choreography",
      "gains": "Centralized control flow — easy to reason about, test, and debug. Compensation order is explicit. Single place to add monitoring, retries, and timeouts.",
      "sacrifices": "Orchestrator is a coordination single point — must be highly available. Services are coupled to the orchestrator's command interface rather than publishing/subscribing to events.",
      "alternatives_considered": ["Choreography-based saga: each service emits events and listens for them. Rejected because with 4 sequential steps and strict reverse compensation, event chains become hard to trace and compensation ordering is error-prone."]
    },
    {
      "decision": "Synchronous command calls with idempotency over async messaging",
      "gains": "Simpler initial implementation, easier to reason about timeouts and retries, no message broker dependency.",
      "sacrifices": "Tighter temporal coupling — if a service is down, the saga blocks. Less natural backpressure.",
      "alternatives_considered": ["Async messaging via a broker (RabbitMQ, Kafka). Better for high-throughput, but adds infrastructure complexity. This is a flexibility point — can migrate to async later without changing the saga state machine logic."]
