      "src/order/OrderService — add cancelOrder endpoint (idempotent)",
      "src/inventory/InventoryService — add releaseItems endpoint (idempotent)",
      "src/payment/PaymentService — add refundPayment endpoint (idempotent)",
      "src/courier/CourierService — add unassignCourier endpoint (idempotent)",
      "src/saga/SagaRecoveryJob — startup/cron job to resume stuck sagas"
    ],
    "patterns_to_follow": "Write-then-act: persist state before invoking external call. Idempotency keys on every command. Declarative step definitions over imperative flow. Compensations retry indefinitely with backoff and alerting. Status queries for timeout disambiguation.",
    "pitfalls_to_avoid": [
      "Do NOT use choreography for this — 4 sequential steps with strict reverse compensation is a textbook orchestration case",
      "Do NOT skip saga state persistence to optimize latency — crash recovery depends on it",
      "Do NOT treat compensation as optional or best-effort — partial compensation leaves the system inconsistent",
      "Do NOT use distributed transactions (2PC) across services — they don't scale and create tight coupling",
      "Do NOT fire compensations in parallel — they must run in reverse sequential order to maintain consistency",
      "Do NOT forget timeout handling — a timeout is neither success nor failure, query the service before deciding"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 92,
    "high_confidence_areas": [
      "Orchestration over choreography — clear win for this sequential, compensation-heavy flow",
      "Compensating transaction design — well-established pattern with known failure modes",
      "State machine modeling — 4 forward steps + 4 compensation steps maps cleanly to a linear state machine",
      "Idempotency requirement — non-negotiable for any saga implementation"
    ],
    "low_confidence_areas": [
      "Courier assignment timeout threshold — 5 minutes is a guess; actual SLA depends on business requirements and courier density",
      "Sync vs async transport choice — defaulted to sync for simplicity, but throughput requirements could change this"
    ],
    "assumptions": [
      "Each service is independently deployable with its own data store (no shared database)",
      "Services can be made idempotent via idempotency keys without major refactoring",
      "The orchestrator has access to a durable store (relational DB or equivalent) for saga state",
      "Order volumes do not require sub-millisecond latency — the per-step persistence write is acceptable",
      "Compensation operations are always semantically possible (e.g., a charged payment can always be refunded)"
    ]
  }
}

